C2FADE_ResetEnemySpriteColorWaveSlot:
    rep #$31
    phd
    pha
    tdc
    adc.w #$FFEE
    tcd
    pla
    txy
    tax
    stx $B37C
    tya
    asl A
    tax
    ; Per-group active timer.
    lda $B37C
    sta $AEF4,X
    ldx.w #$0000
    stx $10
    bra C2FB2E_ResetEnemySpriteColorWaveSlot_LFB2E
C2FAFD_ResetEnemySpriteColorWaveSlot_LFAFD:
    stx $02
    tya
    sta $04
    asl A
    adc $04
    asl A
    asl A
    asl A
    asl A
